class Solution:
    def findDuplicateSubtrees(self, root: Optional[TreeNode]) -> List[Optional[TreeNode]]:
        mp=defaultdict(int); ans=[]
        def ser(n):
            if not n: return "0"
            s=f"{n.val},{ser(n.left)},{ser(n.right)}"
            mp[s]+=1
            if mp[s]==2: ans.append(n)
            return s
        ser(root); return ans

